import { MEAL_TYPES, type Activity, type MealType, type NewActivity, type NewNutritionEntry } from '../types/health.js';
import { AbstractRouteResponses } from './response-helpers.js';
import { parseInteger } from './validation-utils.js';

// --- HTTP contract ---

export interface ApiResponse {
    status: number;
    body?: unknown;
    headers?: Record<string, string>;
}

/**
 * The decoded context passed to every shared route handler.
 * Path parameters are extracted by the adapter (Express or offline router)
 * before calling the handler, so handlers never need to parse paths.
 */
export interface RouteContext {
    params: Record<string, string>;
    query: URLSearchParams;
    body: unknown;
}

// --- Shared health API surface ---

/**
 * Every key in this union is a route that is implemented once in shared code
 * and consumed by both the Express server and the PWA offline router.
 *
 * Server-only routes (OpenFoodFacts proxy, Ollama estimation, calendar
 * activities) are NOT listed here — they are defined exclusively in
 * server/src/modules/sections/health/health.routes.ts.
 */
export type HealthRouteKey =
    | 'GET /activities'
    | 'GET /activities/:id'
    | 'POST /activities'
    | 'PATCH /activities/:id'
    | 'DELETE /activities/:id'
    | 'GET /nutrition/summary'
    | 'GET /nutrition'
    | 'GET /nutrition/:id'
    | 'POST /nutrition'
    | 'PATCH /nutrition/:id'
    | 'DELETE /nutrition/:id'
    | 'GET /food-library/search'
    | 'GET /food-library/recent'
    | 'GET /food-library/frequent'
    | 'GET /food-library/barcode/:barcode'
    | 'GET /food-library/:id'
    | 'POST /food-library/:id/log';

/** Exhaustive TypeScript interface ensuring all routes are implemented. */
export interface IHealthRoutes {
    'GET /activities'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /activities/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /activities'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /activities/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'DELETE /activities/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /nutrition/summary'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /nutrition'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /nutrition/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /nutrition'(ctx: RouteContext): Promise<ApiResponse>;
    'PATCH /nutrition/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'DELETE /nutrition/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-library/search'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-library/recent'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-library/frequent'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-library/barcode/:barcode'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /food-library/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /food-library/:id/log'(ctx: RouteContext): Promise<ApiResponse>;
}

export interface HealthRouteOptions {
    defaultActivitiesRange: { fromDate: string; toDate: string };
}

/**
 * Runtime array of all shared health route keys.
 * Used by adapters (e.g. offline router) that need to iterate routes at runtime.
 */
export const HEALTH_ROUTE_KEYS: readonly HealthRouteKey[] = [
    'GET /activities',
    'GET /activities/:id',
    'POST /activities',
    'PATCH /activities/:id',
    'DELETE /activities/:id',
    'GET /nutrition/summary',
    'GET /nutrition',
    'GET /nutrition/:id',
    'POST /nutrition',
    'PATCH /nutrition/:id',
    'DELETE /nutrition/:id',
    'GET /food-library/search',
    'GET /food-library/recent',
    'GET /food-library/frequent',
    'GET /food-library/barcode/:barcode',
    'GET /food-library/:id',
    'POST /food-library/:id/log',
] as const;

// --- Repository interface ---

export type HealthRepository = {
    getAllActivities(limit?: number): Promise<unknown[]>;
    getActivitiesByDate(date: string): Promise<unknown[]>;
    getActivitiesByDateRange(from: string, to: string): Promise<unknown[]>;
    getActivityById(id: string): Promise<Activity | null>;
    createActivity(activity: NewActivity): Promise<unknown>;
    updateActivity(id: string, updates: Partial<NewActivity>): Promise<unknown | null>;
    deleteActivity(id: string): Promise<boolean>;

    getDateRangeSummary(from: string, to: string): Promise<unknown[]>;
    getNutritionByDate(date: string): Promise<unknown[]>;
    getNutritionByDateRange(from: string, to: string): Promise<unknown[]>;
    getNutritionById(id: string): Promise<unknown | null>;
    createNutritionEntry(entry: NewNutritionEntry): Promise<unknown>;
    updateNutritionEntry(id: string, updates: Partial<NewNutritionEntry>): Promise<unknown | null>;
    deleteNutritionEntry(id: string): Promise<boolean>;

    searchFoodLibrary(query: string, limit?: number): Promise<unknown[]>;
    getRecentFoodLibraryItems(limit?: number): Promise<unknown[]>;
    getFrequentFoodLibraryItems(limit?: number): Promise<unknown[]>;
    getFoodLibraryByBarcode(barcode: string): Promise<unknown | null>;
    getFoodLibraryById(id: string): Promise<unknown | null>;
    createNutritionEntryFromFoodLibraryItem(itemId: string, payload: { date: string; meal_type: MealType }): Promise<unknown | null>;
};

// --- Query validation ---

export interface ResolvedActivitiesQuery {
    mode: 'date' | 'range' | 'default';
    fromDate: string;
    toDate: string;
    date?: string;
}

function isLeapYear(year: number): boolean {
    return year % 400 === 0 || (year % 4 === 0 && year % 100 !== 0);
}

export function isValidIsoDate(value: string): boolean {
    const match = value.match(/^(\d{4})-(\d{2})-(\d{2})$/);
    if (!match) {
        return false;
    }

    const year = Number.parseInt(match[1], 10);
    const month = Number.parseInt(match[2], 10);
    const day = Number.parseInt(match[3], 10);

    if (month < 1 || month > 12 || day < 1) {
        return false;
    }

    const daysInMonth = [
        31,
        isLeapYear(year) ? 29 : 28,
        31,
        30,
        31,
        30,
        31,
        31,
        30,
        31,
        30,
        31,
    ];

    return day <= daysInMonth[month - 1];
}

export function resolveActivitiesQuery(
    query: URLSearchParams,
    defaults: { fromDate: string; toDate: string },
): { error: string } | { value: ResolvedActivitiesQuery } {
    const date = query.get('date');
    const from = query.get('from');
    const to = query.get('to');

    if (date && (from || to)) {
        return { error: 'Use either "date" or "from/to", not both' };
    }

    if ((from && !to) || (!from && to)) {
        return { error: 'Both "from" and "to" are required when using a date range' };
    }

    if (date) {
        if (!isValidIsoDate(date)) {
            return { error: 'Invalid "date" query parameter. Expected YYYY-MM-DD' };
        }

        return {
            value: {
                mode: 'date',
                date,
                fromDate: date,
                toDate: date,
            },
        };
    }

    if (from && to) {
        if (!isValidIsoDate(from) || !isValidIsoDate(to)) {
            return { error: 'Invalid "from" or "to" query parameter. Expected YYYY-MM-DD' };
        }
        if (from > to) {
            return { error: '"from" must be on or before "to"' };
        }
        return {
            value: {
                mode: 'range',
                fromDate: from,
                toDate: to,
            },
        };
    }

    return {
        value: {
            mode: 'default',
            fromDate: defaults.fromDate,
            toDate: defaults.toDate,
        },
    };
}

// --- Abstract Base Class ---

/**
 * Base class for health routing implementations.
 * Encapsulates shared validation logic and response helpers.
 * Subclasses implement context-specific behavior (server vs offline).
 */
export abstract class AbstractHealthRoutes extends AbstractRouteResponses implements IHealthRoutes {
    protected abstract readonly repo: HealthRepository;
    protected readonly options: HealthRouteOptions;

    constructor(options: HealthRouteOptions) {
        super();
        this.options = options;
    }

    protected validateActivitiesQueryResolved(
        query: URLSearchParams,
        defaults: { fromDate: string; toDate: string },
    ): { error: ApiResponse } | { value: ResolvedActivitiesQuery } {
        const resolved = resolveActivitiesQuery(query, defaults);
        if ('error' in resolved) {
            return { error: this.badRequest(resolved.error) };
        }
        return { value: resolved.value };
    }

    async 'GET /activities'({ query }: RouteContext): Promise<ApiResponse> {
        const resolved = resolveActivitiesQuery(query, {
            fromDate: this.options.defaultActivitiesRange.fromDate,
            toDate: this.options.defaultActivitiesRange.toDate,
        });
        if ('error' in resolved) {
            return this.badRequest(resolved.error);
        }

        const { value } = resolved;
        if (value.mode === 'date') {
            return this.ok(await this.repo.getActivitiesByDate(value.date!));
        }
        return this.ok(await this.repo.getActivitiesByDateRange(value.fromDate, value.toDate));
    }

    async 'GET /activities/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const activity = await this.repo.getActivityById(params.id);
        if (!activity) {
            return this.notFound('Activity not found');
        }
        return this.ok(activity);
    }

    async 'POST /activities'({ body: requestBody }: RouteContext): Promise<ApiResponse> {
        const b = (requestBody ?? {}) as Partial<NewActivity>;
        if (!b.type || !b.source || !b.title || !b.date) {
            return this.badRequest('Type, source, title, and date are required');
        }
        const activity = await this.repo.createActivity({
            type: b.type,
            source: b.source,
            title: b.title,
            description: b.description,
            date: b.date,
            duration_minutes: b.duration_minutes,
            calories_burned: b.calories_burned,
            external_id: b.external_id,
            metadata: b.metadata,
        });
        return this.created(activity);
    }

    async 'PATCH /activities/:id'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const existing = await this.repo.getActivityById(params.id);
        if (!existing) {
            return this.notFound('Activity not found');
        }
        if (existing.source !== 'manual') {
            return this.forbidden('Cannot edit synced activities');
        }
        const updated = await this.repo.updateActivity(params.id, (requestBody ?? {}) as Partial<NewActivity>);
        if (!updated) {
            return this.notFound('Activity not found');
        }
        return this.ok(updated);
    }

    async 'DELETE /activities/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const deleted = await this.repo.deleteActivity(params.id);
        if (!deleted) {
            return this.notFound('Activity not found');
        }
        return this.noContent();
    }

    async 'GET /nutrition/summary'({ query }: RouteContext): Promise<ApiResponse> {
        const from = query.get('from');
        const to = query.get('to');
        if (!from || !to) {
            return this.badRequest('Both "from" and "to" query parameters are required');
        }
        return this.ok(await this.repo.getDateRangeSummary(from, to));
    }

    async 'GET /nutrition'({ query }: RouteContext): Promise<ApiResponse> {
        const date = query.get('date');
        const from = query.get('from');
        const to = query.get('to');

        if (from && to) {
            return this.ok(await this.repo.getNutritionByDateRange(from, to));
        }
        if (!date) {
            return this.badRequest('Date or from/to query parameters are required');
        }
        return this.ok(await this.repo.getNutritionByDate(date));
    }

    async 'GET /nutrition/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        const entry = await this.repo.getNutritionById(id);
        if (!entry) {
            return this.notFound('Nutrition entry not found');
        }
        return this.ok(entry);
    }

    async 'POST /nutrition'({ body: requestBody }: RouteContext): Promise<ApiResponse> {
        const b = (requestBody ?? {}) as Partial<NewNutritionEntry>;
        if (!b.date || !b.meal_type || !b.food_name) {
            return this.badRequest('date, meal_type, and food_name are required');
        }
        if (!MEAL_TYPES.includes(b.meal_type as MealType)) {
            return this.badRequest(`meal_type must be one of: ${MEAL_TYPES.join(', ')}`);
        }
        const entry = await this.repo.createNutritionEntry({
            date: b.date,
            meal_type: b.meal_type as MealType,
            food_name: b.food_name,
            serving_size: b.serving_size,
            calories: b.calories,
            protein_g: b.protein_g,
            carbs_g: b.carbs_g,
            fat_g: b.fat_g,
            fiber_g: b.fiber_g,
            sugar_g: b.sugar_g,
            sodium_mg: b.sodium_mg,
            source: b.source ?? 'manual',
            source_ref: b.source_ref,
        });
        return this.created(entry);
    }

    async 'PATCH /nutrition/:id'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        const updated = await this.repo.updateNutritionEntry(id, (requestBody ?? {}) as Partial<NewNutritionEntry>);
        if (!updated) {
            return this.notFound('Nutrition entry not found');
        }
        return this.ok(updated);
    }

    async 'DELETE /nutrition/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        const deleted = await this.repo.deleteNutritionEntry(id);
        if (!deleted) {
            return this.notFound('Nutrition entry not found');
        }
        return this.noContent();
    }

    async 'GET /food-library/search'({ query }: RouteContext): Promise<ApiResponse> {
        const q = (query.get('q') ?? '').trim();
        const limit = parseInteger(query.get('limit') ?? '') ?? 10;
        if (!q) {
            return this.ok([]);
        }
        return this.ok(await this.repo.searchFoodLibrary(q, limit));
    }

    async 'GET /food-library/recent'({ query }: RouteContext): Promise<ApiResponse> {
        const limit = parseInteger(query.get('limit') ?? '') ?? 10;
        return this.ok(await this.repo.getRecentFoodLibraryItems(limit));
    }

    async 'GET /food-library/frequent'({ query }: RouteContext): Promise<ApiResponse> {
        const limit = parseInteger(query.get('limit') ?? '') ?? 10;
        return this.ok(await this.repo.getFrequentFoodLibraryItems(limit));
    }

    async 'GET /food-library/barcode/:barcode'({ params }: RouteContext): Promise<ApiResponse> {
        const barcode = params.barcode.replace(/[^0-9]/g, '');
        if (!barcode) {
            return this.badRequest('Invalid barcode');
        }
        const item = await this.repo.getFoodLibraryByBarcode(barcode);
        if (!item) {
            return this.notFound('Food library item not found');
        }
        return this.ok(item);
    }

    async 'GET /food-library/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        const item = await this.repo.getFoodLibraryById(id);
        if (!item) {
            return this.notFound('Food library item not found');
        }
        return this.ok(item);
    }

    async 'POST /food-library/:id/log'({ params, body: requestBody }: RouteContext): Promise<ApiResponse> {
        const { id } = params;
        if (!id) {
            return this.badRequest('Invalid id');
        }
        const b = (requestBody ?? {}) as { date?: string; meal_type?: MealType };
        if (!b.date || !b.meal_type) {
            return this.badRequest('date and meal_type are required');
        }
        if (!MEAL_TYPES.includes(b.meal_type)) {
            return this.badRequest(`meal_type must be one of: ${MEAL_TYPES.join(', ')}`);
        }
        const entry = await this.repo.createNutritionEntryFromFoodLibraryItem(id, {
            date: b.date,
            meal_type: b.meal_type,
        });
        if (!entry) {
            return this.notFound('Food library item not found');
        }
        return this.created(entry);
    }
}
