import type {
    Activity,
    DailyNutritionSummary,
    FoodLibraryItem,
    MealType,
    NewActivity,
    NewFoodLibraryItem,
    NewNutritionEntry,
    NutritionEntry,
} from '../index.js';
import type { DbDriver } from '../types/db.js';
import { queryOne } from './query-one.js';
import { uuidv7 } from '../utils/uuid.js';

function normalizeFoodName(value: string): string {
    return value.trim().toLowerCase().replace(/\s+/g, ' ');
}

type FoodLibraryUpsertKey =
    | { barcode: string }
    | { source: FoodLibraryItem['source']; source_ref: string }
    | { canonical_name: string; brands?: string | null; source: FoodLibraryItem['source'] };

function resolveLibraryUpsertKey(item: NewFoodLibraryItem): FoodLibraryUpsertKey {
    if (item.barcode) {
        return { barcode: item.barcode };
    }
    if (item.source_ref && item.source !== 'ai_estimate') {
        return { source: item.source, source_ref: item.source_ref };
    }
    return {
        canonical_name: item.canonical_name,
        brands: item.brands ?? null,
        source: item.source,
    };
}

function buildServingSizeText(item: Pick<FoodLibraryItem, 'serving_label' | 'serving_quantity'>): string | undefined {
    if (item.serving_label?.trim()) {
        return item.serving_label.trim();
    }
    if (typeof item.serving_quantity === 'number' && Number.isFinite(item.serving_quantity) && item.serving_quantity > 0) {
        return `${item.serving_quantity}g`;
    }
    return undefined;
}

function parseServingQuantity(value: string | undefined): number | undefined {
    if (!value) return undefined;
    const match = value.match(/(\d+(?:\.\d+)?)\s*(g|ml)\b/i);
    if (!match) return undefined;
    const parsed = Number.parseFloat(match[1]);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : undefined;
}

function buildPer100Json(entry: Pick<NewNutritionEntry, 'serving_size' | 'calories' | 'protein_g' | 'carbs_g' | 'fat_g' | 'fiber_g' | 'sugar_g' | 'sodium_mg'>): string | undefined {
    const quantity = parseServingQuantity(entry.serving_size);
    if (!quantity) return undefined;
    const scale = 100 / quantity;
    return JSON.stringify({
        calories: Math.round((entry.calories ?? 0) * scale * 100) / 100,
        protein_g: Math.round((entry.protein_g ?? 0) * scale * 100) / 100,
        carbs_g: Math.round((entry.carbs_g ?? 0) * scale * 100) / 100,
        fat_g: Math.round((entry.fat_g ?? 0) * scale * 100) / 100,
        fiber_g: Math.round((entry.fiber_g ?? 0) * scale * 100) / 100,
        sugar_g: Math.round((entry.sugar_g ?? 0) * scale * 100) / 100,
        sodium_mg: Math.round((entry.sodium_mg ?? 0) * scale * 100) / 100,
    });
}

export function createHealthRepository(driver: DbDriver) {
    const repository = {
        async getAllActivities(limit = 50): Promise<Activity[]> {
            return driver.query<Activity>('SELECT * FROM activities ORDER BY date DESC LIMIT ?', limit);
        },

        async getActivityById(id: string): Promise<Activity | null> {
            return queryOne<Activity>(driver, 'SELECT * FROM activities WHERE id = ?', id);
        },

        async getActivitiesByDateRange(from: string, to: string): Promise<Activity[]> {
            return driver.query<Activity>('SELECT * FROM activities WHERE date >= ? AND date <= ? ORDER BY date DESC', from, to);
        },

        async getActivitiesByDate(date: string): Promise<Activity[]> {
            return driver.query<Activity>('SELECT * FROM activities WHERE date = ? ORDER BY date DESC', date);
        },

        async getActivityByExternalId(externalId: string): Promise<Activity | null> {
            return queryOne<Activity>(driver, 'SELECT * FROM activities WHERE external_id = ?', externalId);
        },

        async createActivity(activity: NewActivity): Promise<Activity> {
            const id = uuidv7();
            await driver.execute(
                `
                    INSERT INTO activities (id, type, source, title, description, date, duration_minutes, calories_burned, external_id, metadata)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                `,
                id,
                activity.type,
                activity.source,
                activity.title,
                activity.description ?? null,
                activity.date,
                activity.duration_minutes ?? null,
                activity.calories_burned ?? null,
                activity.external_id ?? null,
                activity.metadata ?? null,
            );
            const created = await repository.getActivityById(id);
            if (!created) {
                throw new Error(`Failed to load created activity: ${id}`);
            }
            return created;
        },

        async updateActivity(id: string, updates: Partial<NewActivity>): Promise<Activity | null> {
            const existing = await queryOne<Activity>(driver, 'SELECT * FROM activities WHERE id = ?', id);
            if (!existing) return null;

            const fields: string[] = [];
            const values: unknown[] = [];

            const allowedFields = ['type', 'title', 'description', 'date', 'duration_minutes', 'calories_burned'] as const;
            for (const field of allowedFields) {
                if (field in updates) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }

            if (fields.length === 0) return existing;

            values.push(id);
            await driver.execute(`UPDATE activities SET ${fields.join(', ')} WHERE id = ?`, ...values);
            return queryOne<Activity>(driver, 'SELECT * FROM activities WHERE id = ?', id);
        },

        async deleteActivity(id: string): Promise<boolean> {
            const result = await driver.execute('DELETE FROM activities WHERE id = ?', id);
            return result.changes > 0;
        },

        async createNutritionEntry(entry: NewNutritionEntry): Promise<NutritionEntry> {
            const id = uuidv7();
            await driver.execute(
                `
                    INSERT INTO nutrition_logs (id, date, meal_type, food_name, serving_size, calories, protein_g, carbs_g, fat_g, fiber_g, sugar_g, sodium_mg, source, source_ref, raw_json)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                `,
                id,
                entry.date,
                entry.meal_type,
                entry.food_name,
                entry.serving_size ?? null,
                entry.calories ?? null,
                entry.protein_g ?? null,
                entry.carbs_g ?? null,
                entry.fat_g ?? null,
                entry.fiber_g ?? null,
                entry.sugar_g ?? null,
                entry.sodium_mg ?? null,
                entry.source ?? 'manual',
                entry.source_ref ?? null,
                null,
            );
            const created = await queryOne<NutritionEntry>(driver, 'SELECT * FROM nutrition_logs WHERE id = ?', id);
            if (!created) {
                throw new Error(`Failed to load created nutrition entry: ${id}`);
            }
            await repository.upsertFoodLibraryItem({
                canonical_name: normalizeFoodName(created.food_name),
                display_name: created.food_name,
                barcode: created.source === 'openfoodfacts' ? created.source_ref : undefined,
                serving_label: created.serving_size,
                serving_quantity: parseServingQuantity(created.serving_size),
                calories: created.calories,
                protein_g: created.protein_g,
                carbs_g: created.carbs_g,
                fat_g: created.fat_g,
                fiber_g: created.fiber_g,
                sugar_g: created.sugar_g,
                sodium_mg: created.sodium_mg,
                per_100g_json: (created.source === 'openfoodfacts' || created.source === 'ai_estimate') ? buildPer100Json(created) : undefined,
                source: created.source,
                source_ref: created.source_ref,
                use_count: 1,
            }, { incrementUseCount: true });
            return created;
        },

        async getNutritionByDate(date: string): Promise<NutritionEntry[]> {
            return driver.query<NutritionEntry>('SELECT * FROM nutrition_logs WHERE date = ? ORDER BY meal_type, created_at', date);
        },

        async getNutritionByDateRange(from: string, to: string): Promise<NutritionEntry[]> {
            return driver.query<NutritionEntry>('SELECT * FROM nutrition_logs WHERE date >= ? AND date <= ? ORDER BY date DESC, meal_type, created_at', from, to);
        },

        async getNutritionById(id: string): Promise<NutritionEntry | null> {
            return queryOne<NutritionEntry>(driver, 'SELECT * FROM nutrition_logs WHERE id = ?', id);
        },

        async getDateRangeSummary(from: string, to: string): Promise<DailyNutritionSummary[]> {
            return driver.query<DailyNutritionSummary>(
                `
                    SELECT date,
                           COALESCE(SUM(calories), 0) as total_calories,
                           COALESCE(SUM(protein_g), 0) as total_protein_g,
                           COALESCE(SUM(carbs_g), 0) as total_carbs_g,
                           COALESCE(SUM(fat_g), 0) as total_fat_g,
                           COUNT(*) as entry_count
                    FROM nutrition_logs
                    WHERE date >= ? AND date <= ?
                    GROUP BY date
                    ORDER BY date DESC
                `,
                from,
                to,
            );
        },

        async updateNutritionEntry(id: string, updates: Partial<NewNutritionEntry>): Promise<NutritionEntry | null> {
            const existing = await queryOne<NutritionEntry>(driver, 'SELECT * FROM nutrition_logs WHERE id = ?', id);
            if (!existing) return null;

            const fields: string[] = [];
            const values: unknown[] = [];

            const allowedFields = ['date', 'meal_type', 'food_name', 'serving_size', 'calories', 'protein_g', 'carbs_g', 'fat_g', 'fiber_g', 'sugar_g', 'sodium_mg', 'source', 'source_ref'] as const;
            for (const field of allowedFields) {
                if (field in updates) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }

            if (fields.length === 0) return existing;

            values.push(id);
            await driver.execute(`UPDATE nutrition_logs SET ${fields.join(', ')} WHERE id = ?`, ...values);
            return queryOne<NutritionEntry>(driver, 'SELECT * FROM nutrition_logs WHERE id = ?', id);
        },

        async deleteNutritionEntry(id: string): Promise<boolean> {
            const result = await driver.execute('DELETE FROM nutrition_logs WHERE id = ?', id);
            return result.changes > 0;
        },

        async getFoodLibraryByBarcode(barcode: string): Promise<FoodLibraryItem | null> {
            return queryOne<FoodLibraryItem>(driver, 'SELECT * FROM food_library_items WHERE barcode = ?', barcode);
        },

        async getFoodLibraryById(id: string): Promise<FoodLibraryItem | null> {
            return queryOne<FoodLibraryItem>(driver, 'SELECT * FROM food_library_items WHERE id = ?', id);
        },

        async getFoodLibraryBySourceRef(source: FoodLibraryItem['source'], sourceRef: string): Promise<FoodLibraryItem | null> {
            return queryOne<FoodLibraryItem>(driver, 'SELECT * FROM food_library_items WHERE source = ? AND source_ref = ?', source, sourceRef);
        },

        async searchFoodLibrary(query: string, limit = 10): Promise<FoodLibraryItem[]> {
            const normalized = normalizeFoodName(query);
            return driver.query<FoodLibraryItem>(
                `
                    SELECT *,
                           CASE
                               WHEN canonical_name = ? THEN 0
                               WHEN canonical_name LIKE ? THEN 1
                               WHEN canonical_name LIKE ? THEN 2
                               ELSE 3
                           END AS rank
                    FROM food_library_items
                    WHERE canonical_name LIKE ?
                    ORDER BY rank ASC, use_count DESC, last_used_at DESC, display_name ASC
                    LIMIT ?
                `,
                normalized,
                `${normalized}%`,
                `% ${normalized}%`,
                `%${normalized}%`,
                limit,
            );
        },

        async getFrequentFoodLibraryItems(limit = 10): Promise<FoodLibraryItem[]> {
            return driver.query<FoodLibraryItem>(
                `
                    SELECT * FROM food_library_items
                    ORDER BY use_count DESC, last_used_at DESC, display_name ASC
                    LIMIT ?
                `,
                limit,
            );
        },

        async getRecentFoodLibraryItems(limit = 10): Promise<FoodLibraryItem[]> {
            return driver.query<FoodLibraryItem>(
                `
                    SELECT * FROM food_library_items
                    ORDER BY last_used_at DESC, use_count DESC, display_name ASC
                    LIMIT ?
                `,
                limit,
            );
        },

        async markFoodLibraryItemUsed(id: string): Promise<FoodLibraryItem | null> {
            await driver.execute(
                `
                    UPDATE food_library_items
                    SET use_count = use_count + 1,
                        last_used_at = datetime('now'),
                        updated_at = datetime('now')
                    WHERE id = ?
                `,
                id,
            );
            return repository.getFoodLibraryById(id);
        },

        async upsertFoodLibraryItem(item: NewFoodLibraryItem, options?: { incrementUseCount?: boolean }): Promise<FoodLibraryItem> {
            const key = resolveLibraryUpsertKey(item);
            let existing: FoodLibraryItem | null = null;

            if ('barcode' in key) {
                existing = await queryOne<FoodLibraryItem>(driver, 'SELECT * FROM food_library_items WHERE barcode = ?', key.barcode);
            } else if ('source_ref' in key) {
                existing = await queryOne<FoodLibraryItem>(driver, 'SELECT * FROM food_library_items WHERE source = ? AND source_ref = ?', key.source, key.source_ref);
            } else {
                existing = await queryOne<FoodLibraryItem>(
                    driver,
                    `
                        SELECT * FROM food_library_items
                        WHERE canonical_name = ? AND COALESCE(brands, '') = COALESCE(?, '') AND source = ?
                    `,
                    key.canonical_name,
                    key.brands ?? null,
                    key.source,
                );
            }

            const normalizedItem = {
                canonical_name: normalizeFoodName(item.canonical_name || item.display_name),
                display_name: item.display_name.trim(),
                brands: item.brands ?? null,
                barcode: item.barcode ?? null,
                serving_label: item.serving_label ?? null,
                serving_quantity: item.serving_quantity ?? null,
                calories: item.calories ?? null,
                protein_g: item.protein_g ?? null,
                carbs_g: item.carbs_g ?? null,
                fat_g: item.fat_g ?? null,
                fiber_g: item.fiber_g ?? null,
                sugar_g: item.sugar_g ?? null,
                sodium_mg: item.sodium_mg ?? null,
                per_100g_json: item.per_100g_json ?? null,
                default_amount_json: item.default_amount_json ?? null,
                source: item.source,
                source_ref: item.source_ref ?? null,
                raw_json: item.raw_json ?? null,
                use_count: Math.max(1, item.use_count ?? 1),
                last_used_at: item.last_used_at ?? new Date().toISOString(),
            };

            if (!existing) {
                const newId = uuidv7();
                await driver.execute(
                    `
                        INSERT INTO food_library_items (
                            id, canonical_name, display_name, brands, barcode, serving_label, serving_quantity,
                            calories, protein_g, carbs_g, fat_g, fiber_g, sugar_g, sodium_mg,
                            per_100g_json, default_amount_json, source, source_ref, raw_json, use_count, last_used_at
                        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    `,
                    newId,
                    normalizedItem.canonical_name,
                    normalizedItem.display_name,
                    normalizedItem.brands,
                    normalizedItem.barcode,
                    normalizedItem.serving_label,
                    normalizedItem.serving_quantity,
                    normalizedItem.calories,
                    normalizedItem.protein_g,
                    normalizedItem.carbs_g,
                    normalizedItem.fat_g,
                    normalizedItem.fiber_g,
                    normalizedItem.sugar_g,
                    normalizedItem.sodium_mg,
                    normalizedItem.per_100g_json,
                    normalizedItem.default_amount_json,
                    normalizedItem.source,
                    normalizedItem.source_ref,
                    normalizedItem.raw_json,
                    normalizedItem.use_count,
                    normalizedItem.last_used_at,
                );
                const created = await repository.getFoodLibraryById(newId);
                if (!created) {
                    throw new Error(`Failed to load created food library item: ${newId}`);
                }
                return created;
            }

            const nextUseCount = options?.incrementUseCount ? existing.use_count + Math.max(1, item.use_count ?? 1) : existing.use_count;
            await driver.execute(
                `
                    UPDATE food_library_items
                    SET canonical_name = ?,
                        display_name = ?,
                        brands = ?,
                        barcode = COALESCE(?, barcode),
                        serving_label = COALESCE(?, serving_label),
                        serving_quantity = COALESCE(?, serving_quantity),
                        calories = COALESCE(?, calories),
                        protein_g = COALESCE(?, protein_g),
                        carbs_g = COALESCE(?, carbs_g),
                        fat_g = COALESCE(?, fat_g),
                        fiber_g = COALESCE(?, fiber_g),
                        sugar_g = COALESCE(?, sugar_g),
                        sodium_mg = COALESCE(?, sodium_mg),
                        per_100g_json = COALESCE(?, per_100g_json),
                        default_amount_json = COALESCE(?, default_amount_json),
                        source_ref = COALESCE(?, source_ref),
                        raw_json = COALESCE(?, raw_json),
                        use_count = ?,
                        last_used_at = CASE WHEN ? THEN datetime('now') ELSE last_used_at END,
                        updated_at = datetime('now')
                    WHERE id = ?
                `,
                normalizedItem.canonical_name,
                normalizedItem.display_name,
                normalizedItem.brands,
                normalizedItem.barcode,
                normalizedItem.serving_label,
                normalizedItem.serving_quantity,
                normalizedItem.calories,
                normalizedItem.protein_g,
                normalizedItem.carbs_g,
                normalizedItem.fat_g,
                normalizedItem.fiber_g,
                normalizedItem.sugar_g,
                normalizedItem.sodium_mg,
                normalizedItem.per_100g_json,
                normalizedItem.default_amount_json,
                normalizedItem.source_ref,
                normalizedItem.raw_json,
                nextUseCount,
                options?.incrementUseCount ? 1 : 0,
                existing.id,
            );
            const updated = await repository.getFoodLibraryById(existing.id);
            if (!updated) {
                throw new Error(`Failed to load updated food library item: ${existing.id}`);
            }
            return updated;
        },

        async createNutritionEntryFromFoodLibraryItem(itemId: string, payload: { date: string; meal_type: MealType }): Promise<NutritionEntry | null> {
            const item = await repository.getFoodLibraryById(itemId);
            if (!item) return null;

            return repository.createNutritionEntry({
                date: payload.date,
                meal_type: payload.meal_type,
                food_name: item.display_name,
                serving_size: buildServingSizeText(item),
                calories: item.calories,
                protein_g: item.protein_g,
                carbs_g: item.carbs_g,
                fat_g: item.fat_g,
                fiber_g: item.fiber_g,
                sugar_g: item.sugar_g,
                sodium_mg: item.sodium_mg,
                source: item.source,
                source_ref: item.source_ref,
            });
        },

        async hasImportedFoodLibraryFingerprint(fingerprint: string): Promise<boolean> {
            const row = await queryOne<Record<string, unknown>>(driver, 'SELECT 1 FROM food_library_import_rows WHERE fingerprint = ?', fingerprint);
            return Boolean(row);
        },

        async recordImportedFoodLibraryFingerprint(fingerprint: string, itemId: string): Promise<void> {
            await driver.execute(
                `
                    INSERT OR IGNORE INTO food_library_import_rows (fingerprint, item_id)
                    VALUES (?, ?)
                `,
                fingerprint,
                itemId,
            );
        },
    };

    return repository;
}
