import stylesText from './status-screen.css?inline';
import { cssStyleSheet } from '../../utils/css.js';
import { goBack } from '../../router.js';

import '../status-pill/status-dot/status-dot.component.js';
import './sections/connectivity/connectivity-section.component.js';
import './sections/server/server-section.component.js';
import './sections/sync/sync-section.component.js';
import './sections/credential/credential-section.component.js';
import './sections/services/services-section.component.js';

import { type ServerSection } from './sections/server/server-section.component.js';
import { type SyncSection, type SyncState } from './sections/sync/sync-section.component.js';
import { type CredentialSection } from './sections/credential/credential-section.component.js';
import { type ServicesSection } from './sections/services/services-section.component.js';

import {
    fetchServerStatus,
    isPiGatewayReachable,
    deriveBootStage,
    stageLabel,
    stageColor,
    wake,
    unlock,
    boot,
    shutdown,
    type ServerStatus,
    type BootStage,
    type ActionResult,
} from '../../services/server-control.service.js';
import {
    hasStoredCredential,
    storePassword,
    getPassword,
    clearCredential,
} from '../../services/server-credential.service.js';
import { StravaService, type StravaStatus } from '../../services/strava.service.js';
import { SyncService, type PendingChange } from '../../services/sync/sync.service.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
<header class="screen-header">
    <button class="back-btn" aria-label="Go back">←</button>
    <h1 class="screen-title">System Status</h1>
</header>
<main class="screen-body">
    <div class="section-container">
        <connectivity-status-section id="section-connectivity"></connectivity-status-section>
    </div>
    <div class="section-container">
        <server-status-section id="section-server"></server-status-section>
    </div>
    <div class="section-container">
        <sync-status-section id="section-sync"></sync-status-section>
    </div>
    
    <div class="feedback" id="feedback"></div>

    <div class="section-container">
        <credential-status-section id="section-credential"></credential-status-section>
    </div>
    <div class="section-container">
        <services-status-section id="section-services"></services-status-section>
    </div>
</main>
`;

function formatError(err: unknown): string {
    if (err instanceof Error) return `${err.name}: ${err.message}\n${err.stack ?? ''}`;
    return String(err);
}

export class StatusScreen extends HTMLElement {
    private shadow: ShadowRoot;
    private feedbackEl!: HTMLDivElement;

    // Sections
    private sectionConnectivity!: HTMLElement;
    private sectionServer!: ServerSection;
    private sectionSync!: SyncSection;
    private sectionCredential!: CredentialSection;
    private sectionServices!: ServicesSection;

    // State
    private isOnline = navigator.onLine;
    private serverStage: BootStage = 'unreachable';
    private serverStatus: ServerStatus | null = null;
    private stravaStatus: StravaStatus = { connected: false, last_sync: null };
    private syncState: SyncState = { count: 0, isSyncing: false, failedChange: null, error: null };
    private hasCredential = false;

    private polling: ReturnType<typeof setTimeout> | null = null;
    private consecutivePollFailures = 0;

    private readonly onOnline = () => this.updateConnectivity(true);
    private readonly onOffline = () => this.updateConnectivity(false);
    private readonly onStravaChange = () => void this.refreshStravaStatus();

    constructor() {
        super();
        this.shadow = this.attachShadow({ mode: 'open' });
        this.shadow.adoptedStyleSheets = [styles];
        this.shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        this.feedbackEl = this.shadow.getElementById('feedback') as HTMLDivElement;

        this.sectionConnectivity = this.shadow.getElementById('section-connectivity') as HTMLElement;
        this.sectionServer = this.shadow.getElementById('section-server') as ServerSection;
        this.sectionSync = this.shadow.getElementById('section-sync') as SyncSection;
        this.sectionCredential = this.shadow.getElementById('section-credential') as CredentialSection;
        this.sectionServices = this.shadow.getElementById('section-services') as ServicesSection;

        // Event Listeners
        this.shadow.querySelector('.back-btn')!.addEventListener('click', () => goBack('/'));

        window.addEventListener('online', this.onOnline);
        window.addEventListener('offline', this.onOffline);

        // Server Section Listeners
        this.sectionServer.addEventListener('wake', () => this.doWake());
        this.sectionServer.addEventListener('unlock', () => this.doUnlock());
        this.sectionServer.addEventListener('boot', () => this.doBoot());
        this.sectionServer.addEventListener('shutdown', () => this.doShutdown());
        this.sectionServer.addEventListener('refresh', () => this.refreshServerStatus());

        // Sync Section Listeners
        this.sectionSync.addEventListener('sync', () => this.runSync());
        this.sectionSync.addEventListener('delete-one', (e) => this.deletePendingChange(e.detail));
        this.sectionSync.addEventListener('delete-all', (e) => this.deletePendingChangesFrom(e.detail));

        // Credential Section Listeners
        this.sectionCredential.addEventListener('save', (e) => this.savePassword(e.detail));
        this.sectionCredential.addEventListener('clear', () => this.clearPassword());

        // Services Section Listeners
        this.sectionServices.addEventListener('strava-sync', () => this.syncStrava());
        this.sectionServices.addEventListener('strava-disconnect', () => this.disconnectStrava());
        this.sectionServices.addEventListener('strava-connect', () => this.connectStrava());

        window.addEventListener('strava-connected', this.onStravaChange);
        window.addEventListener('strava-connection-failed', this.onStravaChange);

        this.hasCredential = hasStoredCredential();
        this.sectionCredential.hasCredential = this.hasCredential;

        this.updateConnectivity(navigator.onLine);
        this.schedulePoll(0);
    }

    disconnectedCallback() {
        if (this.polling) clearTimeout(this.polling);
        window.removeEventListener('online', this.onOnline);
        window.removeEventListener('offline', this.onOffline);
        window.removeEventListener('strava-connected', this.onStravaChange);
        window.removeEventListener('strava-connection-failed', this.onStravaChange);
    }

    // ── Polling ──────────────────────────────────────────────────────────────

    private schedulePoll(delayMs: number): void {
        if (this.polling) clearTimeout(this.polling);
        this.polling = setTimeout(() => void this.pollOnce(), delayMs);
    }

    private async pollOnce(): Promise<void> {
        await Promise.all([
            this.refreshServerStatus(),
            this.refreshStravaStatus(),
            this.refreshSyncStatus()
        ]);

        const delay = this.consecutivePollFailures > 0 ? 60_000 : 30_000;
        this.schedulePoll(delay);
    }

    // ── Connectivity ──────────────────────────────────────────────────────────

    private updateConnectivity(online: boolean) {
        this.isOnline = online;
        // The child component ConnectivitySection handles its own local render for online status via its own listeners, 
        // but it's good to keep this state in sync here if needed.
    }

    // ── Server Status ────────────────────────────────────────────────────────

    private async refreshServerStatus(): Promise<void> {
        const reachable = await isPiGatewayReachable();
        if (!reachable) {
            this.applyServerStage('unreachable', null);
            return;
        }
        const status = await fetchServerStatus().catch((err) => {
            console.error('[status-screen] fetchServerStatus failed:', err);
            return null;
        });
        if (!status) {
            this.applyServerStage('unreachable', null);
            return;
        }
        this.applyServerStage(deriveBootStage(status), status);
    }

    private applyServerStage(stage: BootStage, status: ServerStatus | null) {
        this.serverStage = stage;
        this.serverStatus = status;
        this.sectionServer.data = { stage, status };
    }

    // ── Sync Status ──────────────────────────────────────────────────────────

    private async refreshSyncStatus(): Promise<void> {
        try {
            const count = await SyncService.getPendingCount();
            this.syncState.count = count;
            this.updateSyncUI();
        } catch (err) {
            console.error('[status-screen] getPendingCount failed:', err);
            this.syncState.error = err instanceof Error ? `${err.name}: ${err.message}` : String(err);
            this.updateSyncUI();
        }
    }

    private updateSyncUI() {
        this.sectionSync.data = { ...this.syncState };
    }

    private async runSync() {
        if (this.syncState.isSyncing) return;
        this.syncState.isSyncing = true;
        this.syncState.error = null;
        this.syncState.failedChange = null;
        this.updateSyncUI();

        try {
            const result = await SyncService.syncPendingChanges();
            if (result.status === 'synced' || result.status === 'idle') {
                this.showFeedback(`Synced ${result.applied} changes.`, 'ok');
            } else {
                this.syncState.error = result.error;
                this.syncState.failedChange = result.failedChange ?? null;
                this.showFeedback('Sync encountered errors.', 'err');
            }
        } catch (err) {
            const raw = err instanceof Error ? `${err.name}: ${err.message}\n${err.stack ?? ''}` : String(err);
            this.syncState.error = raw;
            this.showFeedback(raw, 'err');
        } finally {
            this.syncState.isSyncing = false;
            await this.refreshSyncStatus();
            this.updateSyncUI();
        }
    }

    private async deletePendingChange(id: number) {
        try {
            await SyncService.deletePendingChange(id);
            this.showFeedback('Change deleted.', 'ok');
            this.syncState.failedChange = null;
            this.syncState.error = null;
            await this.refreshSyncStatus();
        } catch (err) {
            this.showFeedback(formatError(err), 'err');
        }
    }

    private async deletePendingChangesFrom(id: number) {
        try {
            await SyncService.deletePendingChangesFrom(id);
            this.showFeedback('Changes deleted.', 'ok');
            this.syncState.failedChange = null;
            this.syncState.error = null;
            await this.refreshSyncStatus();
        } catch (err) {
            this.showFeedback(formatError(err), 'err');
        }
    }

    // ── Strava Status ────────────────────────────────────────────────────────

    private async refreshStravaStatus(): Promise<void> {
        try {
            this.stravaStatus = await StravaService.getStatus();
        } catch (err) {
            console.error('[status-screen] StravaService.getStatus failed:', err);
            this.stravaStatus = { connected: false, last_sync: null };
        }
        this.sectionServices.stravaStatus = this.stravaStatus;
    }

    private async syncStrava() {
        this.showFeedback('Syncing Strava...', 'ok');
        try {
            const result = await StravaService.sync();
            this.showFeedback(`Strava synced ${result.synced} activities.`, 'ok');
            await this.refreshStravaStatus();
        } catch (err) {
            this.showFeedback(formatError(err), 'err');
        }
    }

    private async disconnectStrava() {
        try {
            await StravaService.disconnect();
            this.showFeedback('Strava disconnected.', 'ok');
            await this.refreshStravaStatus();
        } catch (err) {
            this.showFeedback(formatError(err), 'err');
        }
    }

    private async connectStrava() {
        try {
            const url = await StravaService.getAuthUrl();
            window.location.href = url;
        } catch (err) {
            this.showFeedback(formatError(err), 'err');
        }
    }

    // ── Credentials ──────────────────────────────────────────────────────────

    private savePassword(pw: string) {
        storePassword(pw);
        this.hasCredential = true;
        this.sectionCredential.hasCredential = true;
        this.showFeedback('Password saved for this session.', 'ok');
    }

    private clearPassword() {
        clearCredential();
        this.hasCredential = false;
        this.sectionCredential.hasCredential = false;
        this.showFeedback('Password cleared.', 'ok');
    }

    // ── UI Helpers ───────────────────────────────────────────────────────────

    private showFeedback(message: string, type: 'ok' | 'err') {
        this.feedbackEl.textContent = message;
        this.feedbackEl.className = `feedback feedback--visible feedback--${type}`;
        if (type === 'ok') setTimeout(() => this.clearFeedback(), 5000);
    }

    private clearFeedback() {
        this.feedbackEl.textContent = '';
        this.feedbackEl.className = 'feedback';
    }

    // ── Server Actions Logic ──────────────────

    private async doWake() {
        const result = await wake().catch((e: Error) => ({ success: false, error: e.message }) as ActionResult);
        if (result.success) {
            this.showFeedback(result.message ?? 'WoL packet sent.', 'ok');
            setTimeout(() => void this.refreshServerStatus(), 8_000);
        } else {
            this.showFeedback(result.error ?? 'Wake failed.', 'err');
        }
    }

    private async doUnlock() {
        const pw = getPassword();
        if (!pw) { this.showFeedback('Enter master password first.', 'err'); return; }
        const result = await unlock(pw).catch((e: Error) => ({ success: false, error: e.message }) as ActionResult);
        if (result.success) {
            this.showFeedback(result.message ?? 'Drive decrypted.', 'ok');
            setTimeout(() => void this.refreshServerStatus(), 5_000);
        } else {
            this.showFeedback(result.error ?? 'Unlock failed.', 'err');
        }
    }

    private async doBoot() {
        const pw = getPassword();
        if (!pw) { this.showFeedback('Enter master password first.', 'err'); return; }
        const result = await boot(pw).catch((e: Error) => ({ success: false, error: e.message }) as ActionResult);
        if (result.success) {
            this.showFeedback(result.message ?? 'Booting...', 'ok');
            setTimeout(() => void this.refreshServerStatus(), 10_000);
        } else {
            this.showFeedback(result.error ?? 'Boot failed.', 'err');
        }
    }

    private async doShutdown() {
        const pw = getPassword();
        if (!pw) { this.showFeedback('Enter master password first.', 'err'); return; }
        const result = await shutdown(pw).catch((e: Error) => ({ success: false, error: e.message }) as ActionResult);
        if (result.success) {
            this.showFeedback(result.message ?? 'Shutting down...', 'ok');
            setTimeout(() => void this.refreshServerStatus(), 8_000);
        } else {
            this.showFeedback(result.error ?? 'Shutdown failed.', 'err');
        }
    }
}

customElements.define('status-screen', StatusScreen);
