import type { RouteConfig } from '../../router.js';
import type { ProjectsDashboardScreen } from './projects-dashboard-screen.component.js';
import type { ProjectsScrumboardScreen } from './projects-scrumboard-screen.component.js';
import type { ProjectsStoriesScreen } from './projects-stories-screen.component.js';
import type { ProjectsGitLogScreen } from './projects-git-log-screen.component.js';
import type { ProjectsLogsScreen } from './projects-logs-screen.component.js';

let projectsLoad: Promise<void> | null = null;
const loadProjects = (): Promise<void> => {
    projectsLoad ??= Promise.all([
        import('./projects-dashboard-screen.component.js'),
        import('./projects-scrumboard-screen.component.js'),
        import('./projects-stories-screen.component.js'),
        import('./projects-git-log-screen.component.js'),
        import('./projects-logs-screen.component.js'),
    ]).then(() => undefined);
    return projectsLoad;
};

export function projectsRoutes(): Record<string, RouteConfig> {
    return {
        '/projects': {
            render: async () => {
                await loadProjects();
                return document.createElement('projects-dashboard-screen') as ProjectsDashboardScreen;
            },
        },
        '/projects/scrumboard': {
            render: async () => {
                await loadProjects();
                return document.createElement('projects-scrumboard-screen') as ProjectsScrumboardScreen;
            },
        },
        '/projects/stories': {
            render: async () => {
                await loadProjects();
                return document.createElement('projects-stories-screen') as ProjectsStoriesScreen;
            },
        },
        '/projects/git-log': {
            render: async () => {
                await loadProjects();
                return document.createElement('projects-git-log-screen') as ProjectsGitLogScreen;
            },
        },
        '/projects/logs': {
            render: async () => {
                await loadProjects();
                return document.createElement('projects-logs-screen') as ProjectsLogsScreen;
            },
        },
    };
}
