import type { NewInteraction, NewImportantDate, NewPerson } from '../types/social.js';
import type { SocialRepository } from '../repositories/social.repository.js';
import type { ApiResponse, RouteContext } from './health-routes.js';
import { AbstractRouteResponses } from './response-helpers.js';
import { parseNonEmptyString, parseOptionalNonEmptyString } from './validation-utils.js';

const INTERACTION_TYPES = ['in_person', 'message', 'call', 'video'] as const;

export type SocialRouteKey =
    | 'GET /people'
    | 'GET /people/:id'
    | 'POST /people'
    | 'GET /people/:id/dates'
    | 'POST /people/:id/dates'
    | 'GET /people/:id/interactions'
    | 'POST /people/:id/interactions';

export const SOCIAL_ROUTE_KEYS: readonly SocialRouteKey[] = [
    'GET /people',
    'GET /people/:id',
    'POST /people',
    'GET /people/:id/dates',
    'POST /people/:id/dates',
    'GET /people/:id/interactions',
    'POST /people/:id/interactions',
] as const;

export interface ISocialRoutes {
    'GET /people'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /people/:id'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /people'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /people/:id/dates'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /people/:id/dates'(ctx: RouteContext): Promise<ApiResponse>;
    'GET /people/:id/interactions'(ctx: RouteContext): Promise<ApiResponse>;
    'POST /people/:id/interactions'(ctx: RouteContext): Promise<ApiResponse>;
}

export abstract class AbstractSocialRoutes extends AbstractRouteResponses implements ISocialRoutes {
    protected abstract readonly repo: SocialRepository;

    protected parseString(value: unknown): string | null {
        return parseNonEmptyString(value);
    }

    protected parseOptionalString(value: unknown): string | undefined {
        return parseOptionalNonEmptyString(value);
    }

    abstract 'GET /people'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /people/:id'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'POST /people'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /people/:id/dates'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'POST /people/:id/dates'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'GET /people/:id/interactions'(ctx: RouteContext): Promise<ApiResponse>;
    abstract 'POST /people/:id/interactions'(ctx: RouteContext): Promise<ApiResponse>;
}

export class SocialServerRoutes extends AbstractSocialRoutes {
    protected readonly repo: SocialRepository;

    constructor(repo: SocialRepository) {
        super();
        this.repo = repo;
    }

    async 'GET /people'(): Promise<ApiResponse> {
        return this.ok(await this.repo.getAllPeople());
    }

    async 'GET /people/:id'({ params }: RouteContext): Promise<ApiResponse> {
        const person = await this.repo.getPersonById(params.id);
        if (!person) {
            return this.notFound('Person not found');
        }
        return this.ok(person);
    }

    async 'POST /people'({ body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Partial<NewPerson>;
        const name = this.parseString(b.name);
        if (!name) {
            return this.badRequest('Name is required');
        }

        const person = await this.repo.createPerson({
            name,
            relationship: this.parseOptionalString(b.relationship),
            notes: this.parseOptionalString(b.notes),
            photo_url: this.parseOptionalString(b.photo_url),
        });
        return this.created(person);
    }

    async 'GET /people/:id/dates'({ params }: RouteContext): Promise<ApiResponse> {
        return this.ok(await this.repo.getDatesByPersonId(params.id));
    }

    async 'POST /people/:id/dates'({ params, body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Partial<NewImportantDate>;
        const label = this.parseString(b.label);
        const date = this.parseString(b.date);
        if (!label || !date) {
            return this.badRequest('Label and date are required');
        }

        const importantDate = await this.repo.createImportantDate({
            person_id: params.id,
            label,
            date,
            recurring: b.recurring ?? true,
        });
        return this.created(importantDate);
    }

    async 'GET /people/:id/interactions'({ params }: RouteContext): Promise<ApiResponse> {
        return this.ok(await this.repo.getInteractionsByPersonId(params.id));
    }

    async 'POST /people/:id/interactions'({ params, body }: RouteContext): Promise<ApiResponse> {
        const b = (body ?? {}) as Partial<NewInteraction>;
        const type = this.parseString(b.type);
        const date = this.parseString(b.date);
        if (!type || !date) {
            return this.badRequest('Type and date are required');
        }
        if (!INTERACTION_TYPES.includes(type as (typeof INTERACTION_TYPES)[number])) {
            return this.badRequest(`Type must be one of: ${INTERACTION_TYPES.join(', ')}`);
        }

        const interaction = await this.repo.createInteraction({
            person_id: params.id,
            type: type as NewInteraction['type'],
            date,
            notes: this.parseOptionalString(b.notes),
        });
        return this.created(interaction);
    }
}
