import stylesText from './status-dot.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);

export type DotColor = 'gray' | 'green' | 'orange' | 'red' | 'blue';

export class StatusDot extends HTMLElement {
    private shadow: ShadowRoot;

    static get observedAttributes() {
        return ['color', 'pulse'];
    }

    private dot: HTMLDivElement;

    constructor() {
        super();
        this.shadow = this.attachShadow({ mode: 'open' });
        this.shadow.adoptedStyleSheets = [styles];
        this.dot = document.createElement('div');
        this.dot.className = 'dot';
        this.shadow.appendChild(this.dot);
    }

    connectedCallback() {
        const color = (this.getAttribute('color') ?? 'gray') as DotColor;
        this.dot.classList.add(`dot--${color}`);
        this.updatePulse();
    }

    attributeChangedCallback(name: string, oldValue: string | null, newValue: string | null) {
        if (oldValue === newValue) return;
        if (name === 'color') this.updateColor((oldValue ?? 'gray') as DotColor, newValue as DotColor);
        if (name === 'pulse') this.updatePulse();
    }

    private updateColor(old: DotColor, next: DotColor) {
        this.dot.classList.remove(`dot--${old}`);
        this.dot.classList.add(`dot--${next}`);
    }

    private updatePulse() {
        const pulse = this.hasAttribute('pulse') && this.getAttribute('pulse') !== 'false';
        this.dot.classList.toggle('dot--pulse', pulse);
    }
}

customElements.define('status-dot', StatusDot);
