import { DbService } from './db.service.js';
import { API_URL } from '../config.js';

type SnapshotDbService = Pick<DbService, 'loadFromSnapshot'>;
type PreLoadCheck = () => Promise<boolean> | boolean;

export interface SnapshotDownloadOptions {
    dbService?: SnapshotDbService;
    fetchImpl?: typeof fetch;
    timeoutMs?: number;
    preLoadCheck?: PreLoadCheck;
}

export async function downloadAndLoadSnapshot(options: SnapshotDownloadOptions = {}): Promise<boolean> {
    const {
        dbService = DbService.getInstance(),
        fetchImpl = fetch,
        timeoutMs = 10_000,
    } = options;

    const snapshotUrl = `${API_URL}/api/sync/snapshot`;
    console.log('[SYNC-DEBUG][snapshot] Attempting snapshot download from:', snapshotUrl);

    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), timeoutMs);

    try {
        const response = await fetchImpl(snapshotUrl, {
            method: 'GET',
            cache: 'no-store',
            signal: controller.signal,
        });

        console.log('[SYNC-DEBUG][snapshot] Response status:', response.status, response.statusText);
        if (response.headers) {
            console.log('[SYNC-DEBUG][snapshot] Response headers:', Object.fromEntries(response.headers.entries?.() ?? []));
        }

        if (!response.ok) {
            throw new Error(`Snapshot fetch failed: ${response.status} ${response.statusText}`);
        }

        const buffer = await response.arrayBuffer();
        console.log('[SYNC-DEBUG][snapshot] Downloaded buffer size:', buffer.byteLength, 'bytes');
        if (buffer.byteLength === 0) {
            throw new Error('Snapshot fetch returned an empty payload');
        }

        if (options.preLoadCheck) {
            const shouldProceed = await options.preLoadCheck();
            console.log('[SYNC-DEBUG][snapshot] preLoadCheck result:', shouldProceed);
            if (!shouldProceed) {
                return false;
            }
        }

        console.log('[SYNC-DEBUG][snapshot] Loading snapshot into local DB...');
        await dbService.loadFromSnapshot(buffer);
        console.log('[SYNC-DEBUG][snapshot] Snapshot loaded successfully');
        return true;
    } catch (error) {
        console.warn('Unable to download DB snapshot, continuing without snapshot bootstrap. [SYNC-DEBUG][snapshot] FAILED:', error);
        return false;
    } finally {
        clearTimeout(timeout);
    }
}
