import type { RouteConfig } from '../../router.js';

let agendaLoad: Promise<void> | null = null;
const loadAgenda = (): Promise<void> => {
    agendaLoad ??= import('./agenda.renderer.js').then(() => undefined);
    return agendaLoad;
};

function createAgendaContainer(): HTMLElement {
    const container = document.createElement('div');
    container.className = 'view-section';
    container.id = 'agenda-view';
    return container;
}

export function agendaRoutes(): Record<string, RouteConfig> {
    return {
        '/agenda': {
            render: async () => {
                await loadAgenda();
                const { AgendaRenderer } = await import('./agenda.renderer.js');
                const container = createAgendaContainer();
                const renderer = new AgendaRenderer(container);
                await renderer.init();
                return container;
            },
        },
    };
}
