import { cssStyleSheet } from '../../../../utils/css.js';
import {
    type ServerStatus,
    type BootStage,
    type GatewayState,
    stageColor,
    stageLabel
} from '../../../../services/server-control.service.js';
import type { StatusDot } from '../../../status-pill/status-dot/status-dot.component.js';
import '../../../status-pill/status-dot/status-dot.component.js';

type SectionState = {
    stage: BootStage;
    status: ServerStatus | null;
};

type ServiceKey = keyof ServerStatus;

const SERVICES: ReadonlyArray<{ key: ServiceKey; label: string }> = [
    { key: 'mac', label: 'Network' },
    { key: 'dropbear', label: 'Drive' },
    { key: 'ssh', label: 'OS' },
    { key: 'immich', label: 'Immich' },
];

const ACTIVE_STATES: ReadonlySet<GatewayState> = new Set(['PRESENT', 'LISTENING', 'RUNNING']);

const styles = cssStyleSheet(`
  :host { display: block; }
`);

const template = document.createElement('template');
template.innerHTML = `
    <div class="section">
        <div class="section-header">
            <status-dot id="dot" title="Server"></status-dot>
            <h3 class="section-title" id="title"></h3>
        </div>
        <div class="status-grid" id="grid"></div>
        <div class="actions-row">
            <p id="unreachable-msg" style="margin:0;font-size:0.8rem;opacity:0.5;text-align:center;width:100%" hidden>Not on home network — Pi gateway unreachable.</p>
            <button type="button" class="action-btn action-btn--primary" id="wake-btn" hidden>Wake</button>
            <button type="button" class="action-btn action-btn--primary" id="unlock-btn" hidden>Decrypt Drive</button>
            <button type="button" class="action-btn action-btn--success" id="boot-btn" hidden>Boot Ubuntu</button>
            <button type="button" class="action-btn action-btn--danger" id="shutdown-btn" hidden>Shutdown</button>
            <button type="button" class="action-btn action-btn--primary" id="refresh-btn" hidden>Refresh</button>
        </div>
    </div>
`;

interface ServerSectionEventMap {
    'wake': CustomEvent<void>;
    'unlock': CustomEvent<void>;
    'boot': CustomEvent<void>;
    'shutdown': CustomEvent<void>;
    'refresh': CustomEvent<void>;
}

export interface ServerSection {
    addEventListener<K extends keyof ServerSectionEventMap>(
        type: K,
        listener: (this: ServerSection, ev: ServerSectionEventMap[K]) => unknown,
        options?: boolean | AddEventListenerOptions,
    ): void;
    addEventListener(
        type: string,
        listener: EventListenerOrEventListenerObject,
        options?: boolean | AddEventListenerOptions,
    ): void;
}

export class ServerSection extends HTMLElement {
    private state: SectionState = { stage: 'unreachable', status: null };

    private dot!: StatusDot;
    private sectionTitle!: HTMLHeadingElement;
    private unreachableMsg!: HTMLParagraphElement;
    private badges!: Map<ServiceKey, HTMLSpanElement>;

    private wakeBtn!: HTMLButtonElement;
    private unlockBtn!: HTMLButtonElement;
    private bootBtn!: HTMLButtonElement;
    private shutdownBtn!: HTMLButtonElement;
    private refreshBtn!: HTMLButtonElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        this.dot = shadow.getElementById('dot') as StatusDot;
        this.sectionTitle = shadow.getElementById('title') as HTMLHeadingElement;
        this.unreachableMsg = shadow.getElementById('unreachable-msg') as HTMLParagraphElement;

        this.wakeBtn = shadow.getElementById('wake-btn') as HTMLButtonElement;
        this.unlockBtn = shadow.getElementById('unlock-btn') as HTMLButtonElement;
        this.bootBtn = shadow.getElementById('boot-btn') as HTMLButtonElement;
        this.shutdownBtn = shadow.getElementById('shutdown-btn') as HTMLButtonElement;
        this.refreshBtn = shadow.getElementById('refresh-btn') as HTMLButtonElement;

        this.wakeBtn.addEventListener('click', () => this.emit('wake', this.wakeBtn));
        this.unlockBtn.addEventListener('click', () => this.emit('unlock', this.unlockBtn));
        this.bootBtn.addEventListener('click', () => this.emit('boot', this.bootBtn));
        this.shutdownBtn.addEventListener('click', () => this.emit('shutdown', this.shutdownBtn));
        this.refreshBtn.addEventListener('click', () => this.emit('refresh', this.refreshBtn));

        const grid = shadow.getElementById('grid') as HTMLDivElement;
        this.badges = this.buildGrid(grid);

        this.render();
    }

    private emit(event: string, btn: HTMLButtonElement) {
        btn.disabled = true;
        this.dispatchEvent(new CustomEvent(event));
    }

    set data(next: SectionState) {
        if (this.state.stage === next.stage && this.state.status === next.status) return;
        this.state = next;
        this.render();
    }

    private buildGrid(grid: HTMLDivElement): Map<ServiceKey, HTMLSpanElement> {
        const badges = new Map<ServiceKey, HTMLSpanElement>();
        for (const { key, label } of SERVICES) {
            const row = document.createElement('div');
            row.className = 'status-label';
            row.append(`${label}: `);

            const badge = document.createElement('span');
            badge.className = 'status-badge';
            row.appendChild(badge);

            grid.appendChild(row);
            badges.set(key, badge);
        }
        return badges;
    }

    static getStatus(stage: BootStage) {
        return {
            color: stageColor(stage),
            label: stageLabel(stage)
        };
    }

    private render() {
        const { stage, status } = this.state;
        const pillStatus = ServerSection.getStatus(stage);

        this.dot.setAttribute('color', pillStatus.color);
        this.sectionTitle.textContent = `Server: ${pillStatus.label}`;

        for (const { key } of SERVICES) {
            this.updateBadge(this.badges.get(key)!, status?.[key] ?? null);
        }

        this.renderActions(stage);
    }

    private updateBadge(el: HTMLSpanElement, state: GatewayState | null) {
        const isActive = state !== null && ACTIVE_STATES.has(state);
        el.textContent = state ?? '—';
        el.classList.toggle('status-badge--active', isActive);
        el.classList.toggle('status-badge--inactive', !isActive);
    }

    private renderActions(stage: BootStage) {
        const isUnreachable = stage === 'unreachable';
        this.unreachableMsg.hidden = !isUnreachable;

        this.wakeBtn.hidden = !(stage === 'off' || stage === 'present');
        this.unlockBtn.hidden = stage !== 'dropbear';
        this.bootBtn.hidden = stage !== 'ssh';
        this.shutdownBtn.hidden = stage !== 'running';
        this.refreshBtn.hidden = isUnreachable;

        // Re-enable buttons on render (data update)
        this.wakeBtn.disabled = false;
        this.unlockBtn.disabled = false;
        this.bootBtn.disabled = false;
        this.shutdownBtn.disabled = false;
        this.refreshBtn.disabled = false;
    }
}

customElements.define('server-status-section', ServerSection);
