import type { NotificationsService } from './notifications.service.js';

export interface MessageSource {
    addEventListener(type: 'message', listener: (event: MessageEvent) => void): void;
    removeEventListener(type: 'message', listener: (event: MessageEvent) => void): void;
}

export interface VisibilitySource {
    addEventListener(type: 'visibilitychange', listener: () => void): void;
    removeEventListener(type: 'visibilitychange', listener: () => void): void;
    readonly visibilityState?: DocumentVisibilityState;
}

export interface ClickBridgeDeps {
    serviceWorkerContainer: MessageSource | null;
    navigate: (path: string) => void;
    visibilityTarget?: VisibilitySource;
    notifications: Pick<NotificationsService, 'runLocalChecks'>;
}

export interface IncomingSwMessage {
    action?: string;
    type?: string;
    path?: string;
}

export function attachNotificationClickBridge(deps: ClickBridgeDeps): () => void {
    const disposers: Array<() => void> = [];
    const container = deps.serviceWorkerContainer;

    if (container) {
        const handler = (event: MessageEvent) => {
            const data = event.data as IncomingSwMessage | null;
            if (!data || typeof data !== 'object') return;

            if (data.action === 'navigate' && typeof data.path === 'string') {
                deps.navigate(data.path);
                return;
            }

            if (data.type === 'run-local-checks') {
                const port = event.ports?.[0];
                void deps.notifications.runLocalChecks()
                    .then(() => port?.postMessage({ ok: true }))
                    .catch(() => port?.postMessage({ ok: false }));
            }
        };
        container.addEventListener('message', handler);
        disposers.push(() => container.removeEventListener('message', handler));
    }

    if (deps.visibilityTarget) {
        const target = deps.visibilityTarget;
        const visHandler = () => {
            if (target.visibilityState !== 'visible') return;
            void deps.notifications.runLocalChecks();
        };
        target.addEventListener('visibilitychange', visHandler);
        disposers.push(() => target.removeEventListener('visibilitychange', visHandler));
    }

    return () => {
        for (const dispose of disposers) dispose();
    };
}
