import '../../../status-pill/status-dot/status-dot.component.js';
import type { StatusDot, DotColor } from '../../../status-pill/status-dot/status-dot.component.js';
import type { PendingChange } from '../../../../services/sync/sync.service.js';

export type SyncState = {
    count: number;
    isSyncing: boolean;
    failedChange: PendingChange | null;
    error: string | null;
};

const template = document.createElement('template');
template.innerHTML = `
            <div class="section">
                <div class="section-header">
                    <status-dot id="dot" color="gray" pulse="false" title="Sync"></status-dot>
                    <h3 class="section-title">Sync<span id="sync-count-badge"></span></h3>
                </div>
                <p class="sync-status-msg" id="sync-status-msg">Syncing changes...</p>
                <div class="actions-row" id="sync-actions">
                </div>
            </div>
`;

interface SyncSectionEventMap {
    'sync': CustomEvent<void>;
    'delete-one': CustomEvent<number>;
    'delete-all': CustomEvent<number>;
}

export interface SyncSection {
    addEventListener<K extends keyof SyncSectionEventMap>(
        type: K,
        listener: (this: SyncSection, ev: SyncSectionEventMap[K]) => unknown,
        options?: boolean | AddEventListenerOptions,
    ): void;
    addEventListener(
        type: string,
        listener: EventListenerOrEventListenerObject,
        options?: boolean | AddEventListenerOptions,
    ): void;
}

export class SyncSection extends HTMLElement {
    private shadow: ShadowRoot;
    private state: SyncState = { count: 0, isSyncing: false, failedChange: null, error: null };

    private dot!: StatusDot;
    private countBadge!: HTMLSpanElement;
    private msg!: HTMLParagraphElement;
    private actions!: HTMLDivElement;

    static getStatus(count: number, hasError: boolean) {
        return {
            color: (hasError ? 'red' : count > 0 ? 'orange' : 'green') as DotColor,
            count
        };
    }

    constructor() {
        super();
        this.shadow = this.attachShadow({ mode: 'open' });
        this.shadow.appendChild(template.content.cloneNode(true));
        this.dot = this.shadow.getElementById('dot') as StatusDot;
        this.countBadge = this.shadow.getElementById('sync-count-badge') as HTMLSpanElement;
        this.msg = this.shadow.getElementById('sync-status-msg') as HTMLParagraphElement;
        this.actions = this.shadow.getElementById('sync-actions') as HTMLDivElement;
    }

    set data(next: SyncState) {
        this.state = next;
        this.render();
    }

    private render() {
        const { count, isSyncing, failedChange, error } = this.state;
        const pillStatus = SyncSection.getStatus(count, !!error);

        this.dot.setAttribute('color', pillStatus.color);
        this.dot.setAttribute('pulse', String(isSyncing));
        this.countBadge.textContent = count > 0 ? ` (${count})` : '';
        this.msg.textContent = this.statusMessage();

        this.actions.replaceChildren(...this.buildActionButtons(count, isSyncing, failedChange, error));
    }

    private statusMessage(): string {
        const { isSyncing, error, count } = this.state;
        if (error) return `Sync failed: ${error}`;
        if (isSyncing) return 'Syncing changes...';
        if (count > 0) return `${count} change${count === 1 ? '' : 's'} pending`;
        return 'All changes synced';
    }

    private buildActionButtons(
        count: number,
        isSyncing: boolean,
        failedChange: PendingChange | null,
        error: string | null,
    ): HTMLButtonElement[] {
        const buttons: HTMLButtonElement[] = [];

        if (count > 0 || error) {
            buttons.push(this.makeButton({
                label: isSyncing ? 'Syncing...' : error ? 'Retry Sync' : 'Sync Now',
                variant: 'primary',
                disabled: isSyncing,
                event: 'sync',
            }));
        }

        if (failedChange) {
            const id = failedChange.id;
            buttons.push(this.makeButton({ label: 'Delete Change', variant: 'danger', event: 'delete-one', detail: id }));
            buttons.push(this.makeButton({ label: 'Delete All', variant: 'danger', event: 'delete-all', detail: id }));
        }

        return buttons;
    }

    private makeButton<K extends keyof SyncSectionEventMap>(opts: {
        label: string;
        variant: 'primary' | 'danger';
        event: K;
        disabled?: boolean;
        detail?: SyncSectionEventMap[K]['detail'];
    }): HTMLButtonElement {
        const btn = document.createElement('button');
        btn.className = `action-btn action-btn--${opts.variant}`;
        btn.textContent = opts.label;
        if (opts.disabled) btn.disabled = true;
        btn.onclick = () => this.dispatchEvent(new CustomEvent(opts.event, { detail: opts.detail }));
        return btn;
    }
}

customElements.define('sync-status-section', SyncSection);
