import type { RouteConfig } from '../../router.js';

let goalLoad: Promise<void> | null = null;
const loadGoal = (): Promise<void> => {
    goalLoad ??= import('./goal.renderer.js').then(() => undefined);
    return goalLoad;
};

function createGoalContainer(): HTMLElement {
    const container = document.createElement('div');
    container.className = 'view-section';
    container.id = 'goals-view';
    return container;
}

export function goalRoutes(): Record<string, RouteConfig> {
    return {
        '/goals': {
            render: async () => {
                await loadGoal();
                const { GoalRenderer } = await import('./goal.renderer.js');
                const container = createGoalContainer();
                const renderer = new GoalRenderer(container);
                await renderer.refreshGoals();
                return container;
            },
        },
    };
}
